import chalk from "chalk";
import { spawnSync } from "node:child_process";
import { createInterface } from "node:readline";
import { mkdirSync, readdirSync, unlinkSync, existsSync } from "node:fs";
import { join } from "node:path";
import type { CaiConfig, SyncTarget, DriftIssue } from "../types.js";
import { runDriftCheck } from "../drift/index.js";
import { buildSyncBrief, buildCombinedBrief, type BriefFormat } from "./brief-builder.js";
import { generateRules } from "../rules.js";
import { writeIfChanged } from "../utils/fs.js";

function askUser(question: string): Promise<string> {
  const rl = createInterface({ input: process.stdin, output: process.stdout });
  return new Promise((resolve) => {
    rl.question(question, (answer) => {
      rl.close();
      resolve(answer.trim());
    });
  });
}

const CLAUDE_TIMEOUT_MS = 5 * 60 * 1000; // 5 minutes

function runClaudeInteractive(brief: string, cwd: string): boolean {
  const result = spawnSync("claude", [brief], {
    cwd,
    stdio: "inherit",
    timeout: CLAUDE_TIMEOUT_MS,
  });
  if (result.error) {
    const code = (result.error as NodeJS.ErrnoException).code;
    if (code === "ENOENT") {
      console.error(chalk.red("  claude CLI not found. Install it from https://claude.ai/code"));
    } else if (code === "ETIMEDOUT") {
      console.log(chalk.yellow(`  Claude session timed out after ${CLAUDE_TIMEOUT_MS / 60_000}min. Checking partial results...`));
      return true;
    } else {
      console.error(chalk.red(`  claude failed: ${result.error.message}`));
    }
    return false;
  }
  // 130 = Ctrl+C, 143 = SIGTERM — treat as non-fatal
  if (result.status === 130 || result.status === 143) return false;
  return result.status === 0 || result.status === null;
}

type SyncMode = "interactive" | "prompts";

/** Run targeted sync: detect → brief → AI → verify → ask → loop */
export async function runSync(
  config: CaiConfig,
  opts: { dryRun?: boolean; includeWarnings?: boolean; export?: boolean; format?: BriefFormat; initialReport?: import("../types.js").DriftReport }
): Promise<void> {
  let cycle = 0;
  let mode: SyncMode | null = null;

  while (true) {
    cycle++;

    // Step 1: Run drift check (skip on first cycle if caller already has a fresh report)
    if (cycle === 1) {
      console.log(chalk.bold("Running drift check..."));
      console.log(chalk.dim("  CAI updates your .cai/ scaffold docs to match your code — source files are never changed."));
    } else {
      console.log(chalk.bold("\nRe-checking for remaining drift..."));
    }

    const report = (cycle === 1 && opts.initialReport)
      ? opts.initialReport
      : await runDriftCheck(config, { incremental: cycle > 1 });

    if (cycle === 1) console.log();

    if (report.issues.length === 0) {
      console.log(chalk.green("  ✓ No drift detected — scaffold is in sync."));
      refreshRules(config);
      console.log();
      return;
    }

    const scoreColor = report.score >= 80 ? chalk.green : report.score >= 50 ? chalk.yellow : chalk.red;
    console.log(`  Drift score: ${scoreColor(`${report.score}/100`)}  ${chalk.dim(`(${report.issues.length} issues)`)}`);

    // Step 2: Group issues by file
    const relevantIssues = opts.includeWarnings
      ? report.issues
      : report.issues.filter((i) => {
          const fileHasError = report.issues.some(
            (other) => other.file === i.file && other.severity === "error"
          );
          return fileHasError;
        });

    if (relevantIssues.length === 0) {
      console.log();
      console.log(chalk.green("  ✓ No errors — only warnings remain."));
      console.log(chalk.dim("  Run cai sync --warnings to include them."));
      refreshRules(config);
      console.log();
      return;
    }

    const targets = groupIntoTargets(relevantIssues);

    console.log();
    console.log(chalk.dim("  ─── Files to fix ────────────────────────────────────"));
    for (const target of targets) {
      const errors = target.issues.filter((i) => i.severity === "error").length;
      const warnings = target.issues.filter((i) => i.severity === "warning").length;
      const parts = [errors > 0 ? chalk.red(`${errors} error${errors !== 1 ? "s" : ""}`) : "", warnings > 0 ? chalk.yellow(`${warnings} warning${warnings !== 1 ? "s" : ""}`) : ""].filter(Boolean).join(", ");
      console.log(`  ${chalk.cyan(target.file.padEnd(40))} ${parts}`);
    }
    console.log();

    // Dry run — show combined prompt and exit
    if (opts.dryRun) {
      console.log(
        chalk.dim("\n--dry-run: showing prompt without executing\n")
      );
      const brief = await buildCombinedBrief(targets, config.projectRoot, opts.format);
      console.log(brief);
      console.log();
      return;
    }

    // Export mode — write one prompt file per target into .cai/sync-queue/
    if (opts.export) {
      await exportSyncQueue(targets, config, opts.format);
      return;
    }

    // Ask user for mode (only on first cycle)
    if (mode === null) {
      console.log(chalk.dim("  ─── How should we fix these? ────────────────────────"));
      console.log();
      console.log(`  ${chalk.cyan("1")}  ${chalk.bold("Interactive")}  ${chalk.dim("— Claude fixes everything, you watch (default)")}`);
      console.log(`  ${chalk.cyan("2")}  ${chalk.bold("Export")}       ${chalk.dim("— Write prompt files to .cai/sync-queue/ for manual paste")}`);
      console.log(`  ${chalk.cyan("3")}  ${chalk.bold("Exit")}         ${chalk.dim("— I'll handle it later")}`);
      console.log();

      const choice = await askUser("  Choice [1-3] (default: 1): ");
      const picked = choice || "1";

      switch (picked) {
        case "1":
          mode = "interactive";
          break;
        case "2":
          await exportSyncQueue(targets, config, opts.format);
          return;
        case "3":
          console.log();
          console.log(chalk.dim("  No problem — run cai sync anytime to pick this up."));
          console.log();
          return;
        default:
          console.log();
          console.log(chalk.dim("  No problem — run cai sync anytime to pick this up."));
          console.log();
          return;
      }
    }

    // Step 3: Fix all files in one interactive session
    console.log();
    console.log(chalk.dim(`  Sending ${targets.length} file${targets.length !== 1 ? "s" : ""} to Claude — sit back while it fixes the drift...`));
    console.log();

    const brief = await buildCombinedBrief(targets, config.projectRoot, opts.format);
    const ok = runClaudeInteractive(brief, config.projectRoot);

    if (!ok) {
      console.log(chalk.red("  ✗ Claude session did not complete."));
      console.log(chalk.dim("  Run cai sync again to retry, or cai sync --export to export prompts."));
      console.log();
      return;
    }

    // Step 4: Verify
    const postReport = await runDriftCheck(config);
    const scoreDelta = postReport.score - report.score;
    const deltaStr = scoreDelta > 0 ? chalk.green(`+${scoreDelta}`) : scoreDelta === 0 ? chalk.yellow("+0") : chalk.red(`${scoreDelta}`);

    console.log();
    console.log(chalk.dim("  ─── Result ──────────────────────────────────────────"));
    console.log(`  Drift score: ${chalk.dim(`${report.score}`)} → ${chalk.bold(`${postReport.score}/100`)}  ${chalk.dim(`(${deltaStr})`)} `);
    console.log();

    // Step 5: Check if we should continue
    const remainingErrors = postReport.issues.filter((i) => i.severity === "error").length;
    const remainingWarnings = postReport.issues.filter((i) => i.severity === "warning").length;

    if (postReport.score === 100) {
      console.log(chalk.green("  ✓ Perfect score — everything is in sync."));
      console.log();
      return;
    }

    if (remainingErrors === 0 && !opts.includeWarnings) {
      if (remainingWarnings > 0) {
        console.log(chalk.green("  ✓ All errors resolved."));
        console.log(chalk.dim(`  ${remainingWarnings} warning${remainingWarnings !== 1 ? "s" : ""} remain — run cai sync --warnings to address them.`));
      }
      console.log();
      return;
    }

    const remaining = opts.includeWarnings ? remainingErrors + remainingWarnings : remainingErrors;
    const answer = await askUser(`  ${remaining} issue${remaining !== 1 ? "s" : ""} still remain. Run another round? [Y/n] `);

    if (answer.toLowerCase() === "n") {
      console.log();
      console.log(chalk.dim("  Paused. Run cai sync anytime to continue."));
      console.log();
      return;
    }
    console.log();
  }
}

async function exportSyncQueue(targets: SyncTarget[], config: CaiConfig, format: BriefFormat = "markdown"): Promise<void> {
  const queueDir = join(config.scaffoldRoot, "sync-queue");
  mkdirSync(queueDir, { recursive: true });

  // Clear stale exports from previous runs
  if (existsSync(queueDir)) {
    for (const f of readdirSync(queueDir)) {
      if (f.endsWith(".md") || f.endsWith(".xml")) unlinkSync(join(queueDir, f));
    }
  }

  const written: string[] = [];
  const ext = format === "xml" ? "xml" : "md";

  for (const target of targets) {
    const brief = await buildSyncBrief(target, config.projectRoot, format);
    // Turn "context/architecture.md" → "fix-context-architecture.md"
    const slug = target.file.replace(/\//g, "-").replace(/\.md$/, "");
    const filename = `fix-${slug}.${ext}`;
    const filePath = join(queueDir, filename);
    writeIfChanged(filePath, brief);
    written.push(filename);
  }

  const rel = (p: string) => p.replace(config.projectRoot + "/", "");

  console.log();
  console.log(chalk.bold(`  cai sync --export`));
  console.log();
  console.log(chalk.green(`  ✓ ${written.length} prompt file${written.length === 1 ? "" : "s"} written to ${rel(queueDir)}/`));
  console.log();
  for (const f of written) {
    console.log(chalk.cyan(`    ${rel(queueDir)}/${f}`));
  }
  console.log();
  console.log(chalk.dim("  Open each file, paste the contents into your AI tool,"));
  console.log(chalk.dim("  apply the changes, then run cai check to verify."));
  console.log();
}

/** Regenerate .claude/rules/ after scaffold changes */
function refreshRules(config: CaiConfig): void {
  try {
    const result = generateRules(config);
    if (result.written.length > 0) {
      console.log(chalk.dim(`  ✓ ${result.written.length} path-scoped rules refreshed`));
    }
  } catch {
    // Non-fatal
  }
}

function groupIntoTargets(issues: DriftIssue[]): SyncTarget[] {
  const byFile = new Map<string, DriftIssue[]>();
  for (const issue of issues) {
    if (!byFile.has(issue.file)) byFile.set(issue.file, []);
    byFile.get(issue.file)!.push(issue);
  }

  return Array.from(byFile.entries()).map(([file, issues]) => ({
    file,
    issues,
    gitDiff: null,
  }));
}
